/* Input fields */
.MJX-input {
	position: absolute;
	left: 0px;
	top: 0px;
	/* outline: 2px solid red;
	border: 2px solid blue; */
}

.mjx-math .MJX-input,
mjx-math .MJX-input {
	box-sizing: border-box !important;
}

.mjx-math .MJX-dragAndDropWrapper,
mjx-math .MJX-dragAndDropWrapper {
	position: relative;
	vertical-align: middle;
}

.mjx-math .mathjax-font-resize,
mjx-math .mathjax-font-resize {
	font-size: calc(100% / 1.19);
}

/* For fractions numerator display */
foreignObject .mjx-box.MJXc-stacked {
	position: absolute;
	top: 68%;
}

/* Blank-class / Phantom Spans */
.MJX-blank {
	visibility: hidden;
	position: relative;
	color: rgba(255, 0, 0, 1);
	transition: border 0.2s, box-shadow 0.2s;
}

.MJX-blank:focus-within {
	border: none;
	box-shadow: none;
}

.MJX-slider {
	visibility: visible;
	position: relative;
	line-height: normal;
}

.MJX-dropdownWrapper {
	visibility: visible;
	position: relative;
	transition: border 0.2s, box-shadow 0.2s;
	vertical-align: middle;
}

.MJX-input.MJX-wrong {
	border-color: rgba(230, 148, 148, 1);
}

.MJX-input.MJX-wrong:focus {
	border-color: rgba(255, 132, 132, 1);
}

.MJX-input.MJX-wrong[disabled] {
	border-color: rgba(230, 148, 148, 0.3);
}

